diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index cf6d0ecab4f6..57c196538c86 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -1244,6 +1244,40 @@ static Instruction *foldClampRangeOfTwo(IntrinsicInst *II,
   if (!match(I1, m_APInt(C1)) || !I0->hasOneUse())
     return nullptr;

+  // smin(smax(X, INT_MIN), C) -> X in [INT_MIN, C]
+  // smax(smin(X, INT_MAX), C) -> X in [C, INT_MAX]
+  if (auto *Inner = dyn_cast<MinMaxIntrinsic>(I0)) {
+    if (cast<MinMaxIntrinsic>(II)->isSigned() && Inner->isSigned() && Inner->getLHS()->getType()->isIntOrIntVectorTy()) {
+      Type *Ty = Inner->getLHS()->getType();
+      unsigned BW = Ty->getScalarSizeInBits();
+      const APInt *C2;
+      if (II->getIntrinsicID() == Intrinsic::smin &&
+          Inner->getIntrinsicID() == Intrinsic::smax &&
+          match(Inner->getRHS(), m_APInt(C2)) &&
+          *C2 == APInt::getSignedMinValue(BW)) {
+        APInt Width = *C1 - *C2 + 1;
+        if (!Width.isZero()) {
+          Value *Shifted = Builder.CreateAdd(
+              Inner->getLHS(), ConstantInt::get(Ty, -*C2));
+          return new ICmpInst(ICmpInst::ICMP_ULT, Shifted,
+                              ConstantInt::get(Ty, Width));
+        }
+      }
+      if (II->getIntrinsicID() == Intrinsic::smax &&
+          Inner->getIntrinsicID() == Intrinsic::smin &&
+          match(Inner->getRHS(), m_APInt(C2)) &&
+          *C2 == APInt::getSignedMaxValue(BW)) {
+        APInt Width = *C2 - *C1 + 1;
+        if (!Width.isZero()) {
+          Value *Shifted = Builder.CreateAdd(
+              Inner->getLHS(), ConstantInt::get(Ty, -*C1));
+          return new ICmpInst(ICmpInst::ICMP_ULT, Shifted,
+                              ConstantInt::get(Ty, Width));
+        }
+      }
+    }
+  }
+
   CmpInst::Predicate Pred = CmpInst::BAD_ICMP_PREDICATE;
   switch (II->getIntrinsicID()) {
   case Intrinsic::smax:
@@ -1263,17 +1297,20 @@ static Instruction *foldClampRangeOfTwo(IntrinsicInst *II,
       Pred = ICmpInst::ICMP_ULT;
     break;
   default:
-    llvm_unreachable("Expected min/max intrinsic");
+    return nullptr;
   }
+
   if (Pred == CmpInst::BAD_ICMP_PREDICATE)
     return nullptr;

-  // max (min X, 42), 41 --> X > 41 ? 42 : 41
-  // min (max X, 42), 43 --> X < 43 ? 42 : 43
-  Value *Cmp = Builder.CreateICmp(Pred, X, I1);
-  return SelectInst::Create(Cmp, ConstantInt::get(II->getType(), *C0), I1);
+  return SelectInst::Create(Builder.CreateCmp(Pred, X,
+                                              ConstantInt::get(I1->getType(), *C1)),
+                            ConstantInt::get(I1->getType(), *C1),
+                            ConstantInt::get(I1->getType(), *C0));
 }

+/// If this min/max has a constant operand and an operand that is a matching
+
 /// If this min/max has a constant operand and an operand that is a matching
 /// min/max with a constant operand, constant-fold the 2 constant operands.
 static Value *reassociateMinMaxWithConstants(IntrinsicInst *II,
