/// If we have a clamp pattern like max (min X, 42), 41 -- where the output
/// can only be one of two possible constant values -- turn that into a select
/// of constants.
static Instruction *foldClampRangeOfTwo(IntrinsicInst *II,
                                        InstCombiner::BuilderTy &Builder) {
  Value *I0 = II->getArgOperand(0), *I1 = II->getArgOperand(1);
  Value *X;
  const APInt *C0, *C1;
  if (!match(I1, m_APInt(C1)) || !I0->hasOneUse())
    return nullptr;

  CmpInst::Predicate Pred = CmpInst::BAD_ICMP_PREDICATE;
  switch (II->getIntrinsicID()) {
  case Intrinsic::smax:
    if (match(I0, m_SMin(m_Value(X), m_APInt(C0)))) {
      if (*C0 == *C1 + 1)
        Pred = ICmpInst::ICMP_SGT;
      else if (*C1 == APInt::getSignedMinValue(C1->getBitWidth())) {
        APInt Width = *C0 - *C1 + 1;
        if (!Width.isZero()) {
          Value *Shifted =
              Builder.CreateAdd(X, ConstantInt::get(X->getType(), -*C1));
          return new ICmpInst(ICmpInst::ICMP_ULT, Shifted,
                              ConstantInt::get(X->getType(), Width));
        }
      }
    }
    break;
  case Intrinsic::smin:
    if (match(I0, m_SMax(m_Value(X), m_APInt(C0)))) {
      if (*C1 == *C0 + 1)
        Pred = ICmpInst::ICMP_SLT;
      else if (*C0 == APInt::getSignedMinValue(C0->getBitWidth())) {
        APInt Width = *C1 - *C0 + 1;
        if (!Width.isZero()) {
          Value *Shifted =
              Builder.CreateAdd(X, ConstantInt::get(X->getType(), -*C0));
          return new ICmpInst(ICmpInst::ICMP_ULT, Shifted,
                              ConstantInt::get(X->getType(), Width));
        }
      }
    }
    break;
  case Intrinsic::umax:
    if (match(I0, m_UMin(m_Value(X), m_APInt(C0))) && *C0 == *C1 + 1)
      Pred = ICmpInst::ICMP_UGT;
    break;
  case Intrinsic::umin:
    if (match(I0, m_UMax(m_Value(X), m_APInt(C0))) && *C1 == *C0 + 1)
      Pred = ICmpInst::ICMP_ULT;
    break;
  default:
    return nullptr;
  }

  if (Pred == CmpInst::BAD_ICMP_PREDICATE)
    return nullptr;

  return SelectInst::Create(Builder.CreateCmp(Pred, X, ConstantInt::get(I1->getType(), *C1)),
                            ConstantInt::get(I1->getType(), *C1),
                            ConstantInt::get(I1->getType(), *C0));
}
